# OEIS sequence: A345100

from sympy import bernoulli
def A345100(n):
    c, j = 0, 1
    while j <= n:
        k = n//j
        m = n//k
        c += (bernoulli(k+1,m+1)-bernoulli(k+1,j))//(k+1)
        j = m+1
    return c # _Chai Wah Wu_, May 14 2026

